import React, { useState } from 'react';

const App = () => {
  const [credits, setCredits] = useState(10000);
  const [active, setActive] = useState(true);

  const handleToggle = () => {
    setActive(!active);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] rounded-lg p-4 w-96">
        <h2 className="text-[#C06C88] text-lg font-bold">Model Credits</h2>
        <p className="text-[#411C56] text-sm">{credits}</p>
        <button className="bg-[#C06C88] hover:bg-[#B7D7CD] text-[#B7D7CD] hover:text-[#C06C88] rounded-lg p-2" onClick={handleToggle}>{active ? 'Inactive' : 'Active'}</button>
      </div>
    </div>
  );
};

export default App;
